**Fixed Code:**
```typescript
"use client";

import { useEffect, useState } from "react";
import { useRouter, usePathname } from "next/navigation";
import { useAuthStore } from "@/stores/auth-store";

const PUBLIC_ROUTES = ["/login", "/register", "/forgot-password", "/reset-password", "/"];

export function AuthGuard({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const pathname = usePathname();
  const [isReady, setIsReady] = useState(false);
  const [hydrationTimeout, setHydrationTimeout] = useState(false);

  // Get auth state from Zustand store
  const isAuthenticated = useAuthStore((state) => state.isAuthenticated);
  const user = useAuthStore((state) => state.user);

  useEffect(() => {
    // Set timeout for hydration (5 seconds)
    const timeout = setTimeout(() => {
      setHydrationTimeout(true);
    }, 5000);

    // Wait for Zustand store to hydrate
    // The persist middleware will load from localStorage
    const checkHydration = async () => {
      // Give Zustand time to hydrate from localStorage
      await new Promise((resolve) => setTimeout(resolve, 100));

      // Check if we're on a public route
      if (PUBLIC_ROUTES.includes(pathname)) {
        setIsReady(true);
        clearTimeout(timeout);
        return;
      }

      // Check if user is authenticated
      const state = useAuthStore.getState();
      if (state.isAuthenticated && state.user && state.accessToken) {
        setIsReady(true);
        clearTimeout(timeout);
      } else {
        // Not authenticated, redirect to login
        router.push("/login");
        clearTimeout(timeout);
      }
    };

    checkHydration();

    return () => clearTimeout(timeout);
  }, [pathname, router]);

  // Handle hydration timeout
  if (hydrationTimeout && !isReady) {
    // Fallback: redirect to login if hydration takes too long
    if (!PUBLIC_ROUTES.includes(pathname)) {
      router.push("/login");
    }
    return (
      <div className="flex items-center justify-center h-screen bg-background">
        <div className="text-center">
          <div className="w-10 h-10 rounded-full border-2 border-purple-500/20 border-t-purple-500 animate-spin mx-auto mb-4" />
          <p className="text-sm text-muted-foreground">Loading...</p>
        </div>
      </div>
    );
  }

  if (!isReady) {
    return (
      <div className="flex items-center justify-center h-screen bg-background">
        <div className="text-center">
          <div className="w-10 h-10 rounded-full border-2 border-purple-500/20 border-t-purple-500 animate-spin mx-auto mb-4" />
          <p className="text-sm text-muted-foreground">Authenticating...</p>
        </div>
      </div>
    );
  }

  return <>{children}</>;
}
```

**Key Changes:**
- ✅ Wait for Zustand store hydration (100ms delay)
- ✅ Check `isAuthenticated` flag from store
- ✅ Add 5-second timeout fallback
- ✅ Show loading spinner during hydration
- ✅ Redirect only after hydration complete
- ✅ Handle public routes correctly

**Why This Works:**
- No race condition: Waits for hydration before checking auth
- Proper loading state: Shows spinner while hydrating
- Timeout fallback: Doesn't hang forever
- Correct auth check: Uses Zustand store, not localStorage

---

## Phase 2: Implement Token Refresh

### Task 2.1: Add Token Refresh Logic to API Client

**Already done in Task 1.2** - The `refreshAccessToken()` method handles:
