### Task 2.3: Update Zustand Store with Refresh Handler

**File:** `/apps/web/src/stores/auth-store.ts`

**Add this method to AuthState interface:**
```typescript
interface AuthState {
  // ... existing fields

  refreshTokens: () => Promise<boolean>;
}
```

**Add this implementation to the store:**
```typescript
export const useAuthStore = create<AuthState>()(
  persist(
    (set, get) => ({
      // ... existing methods

      refreshTokens: async () => {
        try {
          const refreshToken = get().refreshToken;
          if (!refreshToken) return false;

          const response = await fetch(
            `${process.env.NEXT_PUBLIC_API_URL || "http://localhost:3378/api/v1"}/auth/refresh`,
            {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ refreshToken }),
            }
          );

          if (!response.ok) return false;

          const data = await response.json();
          if (data.success && data.data) {
            set({
              accessToken: data.data.accessToken,
              refreshToken: data.data.refreshToken,
            });
            return true;
          }

          return false;
        } catch (error) {
          console.error("Token refresh failed:", error);
          return false;
        }
      },
    }),
    {
      name: "audira-auth",
      partialize: (state) => ({
        user: state.user,
        tenant: state.tenant,
        accessToken: state.accessToken,
        refreshToken: state.refreshToken,
        isAuthenticated: state.isAuthenticated,
      }),
    }
  )
);
```

