## Phase 3: Improve Session Validation

### Task 3.1: Add Session Validation Endpoint

**File:** `/apps/api/src/modules/auth/routes.ts`

**Add this endpoint:**
```typescript
// GET /auth/me - Validate session and return current user
authRoutes.get("/me", authMiddleware, async (c) => {
  const user = c.get("user");
  const tenantId = c.get("tenantId");
  const role = c.get("role");

  // Verify session exists in database
  const userId = c.get("userId");
  const session = await prisma.userSession.findFirst({
    where: { userId },
  });

  if (!session) {
    return c.json({ success: false, error: "Session not found" }, 401);
  }

  // Get tenant info
  const tenant = await prisma.tenant.findUnique({
    where: { id: tenantId },
  });

  return c.json({
    success: true,
    data: {
      user,
      tenant,
      role,
    },
  });
});
```

---

### Task 3.2: Add Session Validation on App Load

**File:** `/apps/web/src/components/layout/auth-guard.tsx`

**Update the checkHydration function:**
```typescript
const checkHydration = async () => {
  // Give Zustand time to hydrate from localStorage
  await new Promise((resolve) => setTimeout(resolve, 100));

  // Check if we're on a public route
  if (PUBLIC_ROUTES.includes(pathname)) {
    setIsReady(true);
    clearTimeout(timeout);
    return;
  }

  // Check if user is authenticated locally
  const state = useAuthStore.getState();
  if (!state.isAuthenticated || !state.user || !state.accessToken) {
    router.push("/login");
    clearTimeout(timeout);
    return;
  }

  // Validate session with backend
  try {
    const response = await fetch(
      `${process.env.NEXT_PUBLIC_API_URL || "http://localhost:3378/api/v1"}/auth/me`,
      {
        headers: {
          Authorization: `Bearer ${state.accessToken}`,
        },
      }
    );

    if (response.ok) {
      const data = await response.json();
      if (data.success) {
        // Session is valid
        setIsReady(true);
        clearTimeout(timeout);
        return;
      }
    }

    // Session invalid, redirect to login
    useAuthStore.getState().logout();
    router.push("/login");
  } catch (error) {
    // Network error - allow access but log it
    console.warn("Could not validate session with backend:", error);
    setIsReady(true);
    clearTimeout(timeout);
  }
};
```

